+fn fuzz_python_floor_div_i64(lhs: i64, rhs: i64) -> i64 {
+    debug_assert_ne!(rhs, 0);
+    if lhs == i64::MIN && rhs == -1 {
+        return i64::MIN;
+    }
+
+    let quotient = lhs / rhs;
+    let remainder = lhs % rhs;
+    if remainder != 0 && ((remainder > 0) != (rhs > 0)) {
+        quotient - 1
+    } else {
+        quotient
+    }
+}
